import { Checkbox as CheckboxRoot, type CheckboxProps, type CheckboxVariant } from "./checkbox";
import { CheckboxGroup, type CheckboxGroupProps } from "./checkbox-group";
import { CheckboxItem, type CheckboxItemProps } from "./checkbox-item";

const Checkbox = Object.assign(CheckboxRoot, {
  Group: CheckboxGroup,
  Item: CheckboxItem,
});

export { Checkbox, type CheckboxProps, type CheckboxVariant };
export { CheckboxGroup, type CheckboxGroupProps };
export { CheckboxItem, type CheckboxItemProps };

"use client";

import { useId, type KeyboardEvent as ReactKeyboardEvent, type ReactNode, type Ref } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import {
  selectableVariants,
  selectableContainerClass,
  selectableIndicatorVariants,
  selectableLabelVariants,
  selectableDescriptionVariants,
  selectableIndicators,
  type SelectableSize,
  type SelectableVariant,
} from "@/lib/selectable-variants";
import { cn } from "@/lib/utils";

function resolveCheckboxState(indeterminate: boolean, checked: boolean) {
  if (indeterminate) return "indeterminate" as const;
  if (checked) return "checked" as const;
  return "unchecked" as const;
}

export type CheckboxSize = SelectableSize;

export type CheckboxVariant = SelectableVariant;

export type CheckboxProps = {
  checked?: boolean | "indeterminate";
  defaultChecked?: boolean;
  onChange?: (checked: boolean) => void;
  onMouseEnter?: () => void;
  label?: ReactNode;
  description?: ReactNode;
  disabled?: boolean;
  highlighted?: boolean;
  size?: CheckboxSize;
  variant?: CheckboxVariant;
  strikethrough?: boolean;
  value?: string;
  name?: string;
  required?: boolean;
  invalid?: boolean;
  "aria-label"?: string;
  "aria-invalid"?: boolean;
  className?: string;
  "data-value"?: string;
  ref?: Ref<HTMLDivElement>;
};

export function Checkbox({
  checked: controlledChecked,
  defaultChecked = false,
  onChange,
  onMouseEnter,
  label,
  description,
  disabled = false,
  highlighted = false,
  size = "md",
  variant = "x",
  strikethrough = false,
  value = "on",
  name,
  required,
  invalid,
  "aria-label": ariaLabel,
  "aria-invalid": ariaInvalid,
  className,
  "data-value": dataValue,
  ref,
}: CheckboxProps) {
  const generatedId = useId();
  const labelId = `${generatedId}-label`;
  const descriptionId = `${generatedId}-desc`;
  const isIndeterminate = controlledChecked === "indeterminate";
  const controlledBool = controlledChecked === undefined
    ? undefined
    : controlledChecked === true;

  const [isChecked, setIsChecked] = useControllableState<boolean>({
    value: controlledBool,
    defaultValue: defaultChecked,
    onChange,
  });
  const state = resolveCheckboxState(isIndeterminate, isChecked);

  const toggle = () => {
    if (disabled) return;
    setIsChecked(!isChecked);
  };

  const handleKeyDown = (e: ReactKeyboardEvent) => {
    if (e.key === " ") {
      e.preventDefault();
      toggle();
    }
  };

  const indicator = selectableIndicators[variant][state];

  return (
    <div
      ref={ref}
      role="checkbox"
      data-value={dataValue}
      aria-checked={isIndeterminate ? "mixed" : isChecked}
      aria-disabled={disabled || undefined}
      aria-required={required || undefined}
      aria-invalid={invalid || ariaInvalid || undefined}
      aria-label={ariaLabel}
      aria-labelledby={!ariaLabel && label ? labelId : undefined}
      aria-describedby={description ? descriptionId : undefined}
      tabIndex={disabled ? -1 : 0}
      onClick={toggle}
      onKeyDown={handleKeyDown}
      onMouseEnter={onMouseEnter}
      className={cn(
        selectableVariants({ highlighted, disabled }),
        selectableContainerClass,
        description && "items-start",
        className,
      )}
    >
      <input
        type="checkbox"
        name={name}
        value={value}
        checked={isChecked}
        required={required}
        disabled={disabled}
        className="sr-only"
        tabIndex={-1}
        readOnly
        aria-hidden="true"
      />
      <span aria-hidden="true" className={selectableIndicatorVariants({ size, checked: isChecked, highlighted })}>
        {indicator}
      </span>
      {label && (
        <div className={cn("flex flex-col min-w-0", !description && "justify-center")}>
          <span id={labelId} className={cn(selectableLabelVariants({ size }), strikethrough && isChecked && "text-muted-foreground line-through")}>{label}</span>
          {description && (
            <span id={descriptionId} className={selectableDescriptionVariants({ highlighted })}>{description}</span>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffectEvent, useMemo, useRef, type KeyboardEvent as ReactKeyboardEvent, type ReactNode, type Ref } from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { useControllableState } from "@/hooks/use-controllable-state";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import type { SelectableVariant } from "@/lib/selectable-variants";
import type { CheckboxSize } from "./checkbox";
import { CheckboxGroupContext } from "./checkbox-group-context";

export type CheckboxGroupProps<T extends string = string> = {
  value?: T[];
  defaultValue?: T[];
  onChange?: (value: T[]) => void;
  onHighlightChange?: (value: string) => void;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
  highlighted?: string | null;
  wrap?: boolean;
  disabled?: boolean;
  size?: CheckboxSize;
  variant?: SelectableVariant;
  strikethrough?: boolean;
  name?: string;
  required?: boolean;
  className?: string;
  label?: string;
  labelledBy?: string;
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
};

export function CheckboxGroup<T extends string = string>({
  value: controlledValue,
  defaultValue = [] as T[],
  onChange,
  onHighlightChange,
  onKeyDown,
  highlighted: controlledHighlighted,
  wrap = true,
  disabled = false,
  size = "md",
  variant = "x",
  strikethrough = false,
  name,
  required,
  className,
  label,
  labelledBy,
  children,
  ref,
}: CheckboxGroupProps<T>) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [value, setValue] = useControllableState<T[]>({
    value: controlledValue,
    defaultValue,
    onChange,
  });

  const [highlightedValue, setHighlightedValue] = useControllableState<string | null>({
    value: controlledHighlighted,
    defaultValue: null,
    onChange: onHighlightChange as ((value: string | null) => void) | undefined,
  });

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "checkbox",
    wrap,
    value: highlightedValue ?? undefined,
    onValueChange: setHighlightedValue,
  });

  const stableOnHighlightChange = useEffectEvent((value: string) => setHighlightedValue(value));

  const toggle = useEffectEvent((itemValue: string) => {
    if (disabled) return;
    const typed = itemValue as T;
    setValue((cur) => (cur.includes(typed) ? cur.filter((v) => v !== typed) : [...cur, typed]));
  });

  const handleKeyDown = (e: ReactKeyboardEvent) => {
    onKeyDown?.(e);
    if (!e.defaultPrevented && e.key !== " ") navKeyDown(e);
  };

  const contextValue = useMemo(() => ({ value, toggle, disabled, size, variant, strikethrough, onHighlightChange: stableOnHighlightChange, highlightedValue: highlightedValue ?? null, name, required }), [value, disabled, size, variant, strikethrough, highlightedValue, name, required]);

  return (
    <CheckboxGroupContext value={contextValue}>
      <div
        ref={composeRefs(containerRef, ref)}
        role="group"
        aria-label={label}
        aria-labelledby={labelledBy}
        aria-disabled={disabled || undefined}
        aria-required={required || undefined}
        className={cn("flex flex-col gap-2", className)}
        onKeyDown={handleKeyDown}
      >
        {children}
      </div>
    </CheckboxGroupContext>
  );
}

"use client";

import type { ReactNode, Ref } from "react";
import { Checkbox } from "./checkbox";
import { useCheckboxGroupContext } from "./checkbox-group-context";

export type CheckboxItemProps = {
  value: string;
  label: ReactNode;
  description?: ReactNode;
  disabled?: boolean;
  className?: string;
  ref?: Ref<HTMLDivElement>;
};

export function CheckboxItem({ value, label, description, disabled = false, className, ref }: CheckboxItemProps) {
  const ctx = useCheckboxGroupContext();
  const isDisabled = disabled || ctx.disabled;

  return (
    <Checkbox
      ref={ref}
      value={value}
      data-value={value}
      checked={ctx.value.includes(value)}
      onChange={() => ctx.toggle(value)}
      onMouseEnter={isDisabled ? undefined : () => ctx.onHighlightChange?.(value)}
      label={label}
      description={description}
      disabled={isDisabled}
      highlighted={ctx.highlightedValue === value}
      size={ctx.size}
      variant={ctx.variant}
      strikethrough={ctx.strikethrough}
      name={ctx.name}
      required={ctx.required}
      className={className}
    />
  );
}

"use client";

import { createContext, useContext } from "react";
import type { SelectableVariant } from "@/lib/selectable-variants";
import type { CheckboxSize } from "./checkbox";

export type CheckboxGroupContextValue = {
  value: string[];
  toggle: (itemValue: string) => void;
  disabled: boolean;
  size: CheckboxSize;
  variant: SelectableVariant;
  strikethrough: boolean;
  onHighlightChange?: (value: string) => void;
  highlightedValue: string | null;
  name?: string;
  required?: boolean;
};

export const CheckboxGroupContext = createContext<CheckboxGroupContextValue | undefined>(undefined);

export function useCheckboxGroupContext() {
  const context = useContext(CheckboxGroupContext);
  if (!context) throw new Error("CheckboxItem must be used within CheckboxGroup");
  return context;
}
